	aes128Decrypt,
	aes128Encrypt,
	aes128RandomKey,
	base64ToUint8Array,
	bitArrayToUint8Array,
	decryptKey,
	ENABLE_MAC,
	encryptKey,
	IV_BYTE_LENGTH,
	random,
	uint8ArrayToBase64,
} from "@tutao/tutanota-crypto"
import { downcast, neverNull, stringToUtf8Uint8Array } from "@tutao/tutanota-utils"
import {
	createEncryptedMailAddress,
	createMail,
	createMailAddress,
	MailDetailsDraftTypeRef,
	MailTypeRef,
	createDraftDetails,
	createMailDetailsDraft,
} from "/app/src/api/entities/tutanota/TypeRefs.js"
import { CryptoFacade } from "/app/src/api/worker/crypto/CryptoFacade.js"
import { EntityClient } from "/app/src/api/common/EntityClient.js"
import { RestClient } from "/app/src/api/worker/rest/RestClient.js"
import { InstanceMapper } from "/app/src/api/worker/crypto/InstanceMapper.js"
import { RsaWeb } from "/app/src/api/worker/crypto/RsaImplementation.js"
import { UserFacade } from "/app/src/api/worker/facades/UserFacade.js"
import { SessionKeyNotFoundError } from "/app/src/api/common/error/SessionKeyNotFoundError.js"
import { OwnerEncSessionKeysUpdateQueue } from "/app/src/api/worker/crypto/OwnerEncSessionKeysUpdateQueue.js"
import { object, when } from "testdouble"
import { resolveTypeReference } from "/app/src/api/common/EntityFunctions.js"

describe("Regression: Non-legacy mail content decryption with missing key propagation", function () {
	let crypto: CryptoFacade
	let entityClient: EntityClient
	let userFacade: UserFacade
	let restClient: RestClient
	let instanceMapper: InstanceMapper
	let rsa: RsaWeb
	let mailGroupKey: any
	let ownerGroupId: string

	beforeEach(async function () {
		rsa = new RsaWeb()
		instanceMapper = new InstanceMapper()
		const suspensionHandler = downcast({})
		restClient = new RestClient(suspensionHandler)

		userFacade = object()
		entityClient = object()

		// Mock the userFacade to return a group key
		mailGroupKey = aes128RandomKey()
		ownerGroupId = "owner-group-id"

		when(userFacade.isFullyLoggedIn()).thenReturn(true)
		when(userFacade.hasGroup(ownerGroupId)).thenReturn(true)
		when(userFacade.getGroupKey(ownerGroupId)).thenReturn(mailGroupKey)

		const ownerEncSessionKeysUpdateQueue = object()
		const serviceExecutor = object()

		crypto = new CryptoFacade(userFacade, entityClient, restClient, rsa, serviceExecutor, instanceMapper, ownerEncSessionKeysUpdateQueue)
	})

	test("Load non-legacy mail MailDetailsDraft without ownerKey propagation should fail", async function () {
		// Setup: Create a non-legacy Mail with owner-encrypted session key
		const mailGroupKey = aes128RandomKey()
		const mailSessionKey = aes128RandomKey()
		const ownerGroupId = "owner-group-id"

		// Create a mail with ownerEncSessionKey
		const mail = createMail({
			_id: ["mail-list-id", "mail-id"],
			_ownerGroup: ownerGroupId,
			_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(mailGroupKey, mailSessionKey)),
			mailDetailsDraft: ["details-draft-list-id", "details-draft-id"],
			subject: "Test Subject",
			sender: createMailAddress({
				address: "sender@example.com",
				name: "Sender",
			}),
		})

		// Create MailDetailsDraft WITHOUT ownerEncSessionKey (represents new permission model)
		// In the new permission model, MailDetailsDraft might not have its own session key
		const mailDetailsDraft = createMailDetailsDraft({
			_id: ["details-draft-list-id", "details-draft-id"],
			_ownerGroup: null, // No owner group
			_ownerEncSessionKey: null, // No owner-encrypted session key
			_permissions: "permissions-id",
			details: createDraftDetails({
				replyTos: [
					createEncryptedMailAddress({
						address: "reply-to@example.com",
						name: "Reply To",
					}),
				],
			}),
		})

		// Encrypt the mailDetailsDraft content with the mailSessionKey
		const typeModel = await resolveTypeReference(MailDetailsDraftTypeRef)
		const encryptedDetailsBody = uint8ArrayToBase64(
			aes128Encrypt(
				mailSessionKey,
				stringToUtf8Uint8Array(JSON.stringify(mailDetailsDraft.details)),
				random.generateRandomData(IV_BYTE_LENGTH),
				true,
				ENABLE_MAC
			)
		)

		const encryptedMailDetailsDraft = {
			...mailDetailsDraft,
			details: encryptedDetailsBody, // Simulate server-side encrypted data
		}

		// Mock entityClient to return the encrypted MailDetailsDraft
		// When loading MailDetailsDraft without the session key, it should fail
		when(entityClient.load(MailDetailsDraftTypeRef, ["details-draft-list-id", "details-draft-id"], undefined, undefined, undefined)).thenResolve(
			encryptedMailDetailsDraft
		)

		// First, resolve the mail's session key to cache it
		const mailTypeModel = await resolveTypeReference(MailTypeRef)
		const resolvedMailSessionKey = await crypto.resolveSessionKey(mailTypeModel, mail)
		expect(resolvedMailSessionKey).not.toBeNull()

		// Now try to load the MailDetailsDraft without passing the ownerKey
		// This simulates what happens when the application tries to load related entities
		// without proper key propagation
		try {
			const loadedDraft = await entityClient.load(MailDetailsDraftTypeRef, ["details-draft-list-id", "details-draft-id"])
			const resolvedDraftSessionKey = await crypto.resolveSessionKey(typeModel, loadedDraft)

			// If we get here, the bug is NOT present - the key was somehow resolved
			// But in the non-legacy model, this should fail without the ownerKey
			// We expect the session key to be null indicating decryption failure
			expect(resolvedDraftSessionKey === null).toBe(true)
		} catch (e) {
			// This is the expected behavior - the session key cannot be resolved
			// because it's not in the permissions and the ownerKey wasn't passed
			expect(e instanceof SessionKeyNotFoundError).toBe(true)
		}
	})

	test("Load non-legacy mail with ownerKey propagation should succeed", async function () {
		// Setup: Create a non-legacy Mail with owner-encrypted session key
		const mailGroupKey = aes128RandomKey()
		const mailSessionKey = aes128RandomKey()
		const ownerGroupId = "owner-group-id"

		// Create a mail with ownerEncSessionKey
		const mail = createMail({
			_id: ["mail-list-id", "mail-id"],
			_ownerGroup: ownerGroupId,
			_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(mailGroupKey, mailSessionKey)),
			mailDetailsDraft: ["details-draft-list-id", "details-draft-id"],
			subject: "Test Subject",
			sender: createMailAddress({
				address: "sender@example.com",
				name: "Sender",
			}),
		})

		// Create MailDetailsDraft WITHOUT ownerEncSessionKey (represents new permission model)
		const draftDetails = createDraftDetails({
			replyTos: [
				createEncryptedMailAddress({
					address: "reply-to@example.com",
					name: "Reply To",
				}),
			],
		})

		const mailDetailsDraft = createMailDetailsDraft({
			_id: ["details-draft-list-id", "details-draft-id"],
			_ownerGroup: null, // No owner group
			_ownerEncSessionKey: null, // No owner-encrypted session key
			_permissions: "permissions-id",
			details: draftDetails,
		})

		// If the ownerKey were properly propagated, we could decrypt with the mail's session key
		// Decrypt a test to show it would work
		const testText = "test content"
		const encryptedTest = uint8ArrayToBase64(
			aes128Encrypt(mailSessionKey, stringToUtf8Uint8Array(testText), random.generateRandomData(IV_BYTE_LENGTH), true, ENABLE_MAC)
		)

		const decryptedTest = new TextDecoder().decode(
			aes128Decrypt(mailSessionKey, base64ToUint8Array(encryptedTest), true)
		)
		expect(decryptedTest).toBe(testText)
	})

	test("Batch loading multiple non-legacy mails without key propagation should fail", async function () {
		const mailGroupKey = aes128RandomKey()
		const mailSessionKey1 = aes128RandomKey()
		const mailSessionKey2 = aes128RandomKey()
		const ownerGroupId = "owner-group-id"

		// Create two mails with different session keys
		const mail1 = createMail({
			_id: ["mail-list-id", "mail-id-1"],
			_ownerGroup: ownerGroupId,
			_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(mailGroupKey, mailSessionKey1)),
			mailDetailsDraft: ["details-draft-list-id", "details-draft-id-1"],
			subject: "Test Subject 1",
			sender: createMailAddress({
				address: "sender@example.com",
				name: "Sender",
			}),
		})

		const mail2 = createMail({
			_id: ["mail-list-id", "mail-id-2"],
			_ownerGroup: ownerGroupId,
			_ownerEncSessionKey: bitArrayToUint8Array(encryptKey(mailGroupKey, mailSessionKey2)),
			mailDetailsDraft: ["details-draft-list-id", "details-draft-id-2"],
			subject: "Test Subject 2",
			sender: createMailAddress({
				address: "sender2@example.com",
				name: "Sender 2",
			}),
		})

		// Create MailDetailsDrafts WITHOUT ownerEncSessionKey
		const mailDetailsDraft1 = createMailDetailsDraft({
			_id: ["details-draft-list-id", "details-draft-id-1"],
			_ownerGroup: null,
			_ownerEncSessionKey: null,
			_permissions: "permissions-id",
			details: createDraftDetails({
				replyTos: [
					createEncryptedMailAddress({
						address: "reply-to-1@example.com",
						name: "Reply To 1",
					}),
				],
			}),
		})

		const mailDetailsDraft2 = createMailDetailsDraft({
			_id: ["details-draft-list-id", "details-draft-id-2"],
			_ownerGroup: null,
			_ownerEncSessionKey: null,
			_permissions: "permissions-id",
			details: createDraftDetails({
				replyTos: [
					createEncryptedMailAddress({
						address: "reply-to-2@example.com",
						name: "Reply To 2",
					}),
				],
			}),
		})

		// In batch loading, each mail would have a different session key,
		// but this information is not propagated when loading the MailDetailsDrafts
		const typeModel = await resolveTypeReference(MailDetailsDraftTypeRef)

		// Resolve the mails' session keys (they would be cached)
		const mailTypeModel = await resolveTypeReference(MailTypeRef)
		const resolvedMailSessionKey1 = await crypto.resolveSessionKey(mailTypeModel, mail1)
		const resolvedMailSessionKey2 = await crypto.resolveSessionKey(mailTypeModel, mail2)

		expect(resolvedMailSessionKey1).not.toBeNull()
		expect(resolvedMailSessionKey2).not.toBeNull()

		// When loading the MailDetailsDrafts in batch without the per-entity ownerKey,
		// both should fail or return entities with _errors set
		when(entityClient.loadMultiple(MailDetailsDraftTypeRef, "details-draft-list-id", ["details-draft-id-1", "details-draft-id-2"])).thenResolve([
			mailDetailsDraft1,
			mailDetailsDraft2,
		])

		const loadedDrafts = await entityClient.loadMultiple(MailDetailsDraftTypeRef, "details-draft-list-id", ["details-draft-id-1", "details-draft-id-2"])
		expect(loadedDrafts.length).toBe(2)

		// Without proper key propagation, these entities would have decryption failures
		// The details field would not be properly decrypted
		for (const draft of loadedDrafts) {
			// Check if the draft has errors (indicating decryption failure)
			// In the buggy implementation, these would have _errors set
			expect(draft._errors || draft.details === null).toBe(true)
		}
	})
})
"}

